import{_ as e,c as r,o,aQ as a,bb as s}from"./chunks/framework.BICMMsAb.js";const _=JSON.parse('{"title":"关于本站","description":"Insight Stack 是一个探索全栈工程、产品思维与 LLM 交叉领域的数字花园。","frontmatter":{"date":"2025-08-29T09:40:53.000Z","title":"关于本站","description":"Insight Stack 是一个探索全栈工程、产品思维与 LLM 交叉领域的数字花园。","coverImg":"/img/cover/about_site_bg.png","permalink":"/about/site","categories":["关于"]},"headers":[],"relativePath":"40.关于/02.关于本站.md","filePath":"40.关于/02.关于本站.md"}'),n={name:"40.关于/02.关于本站.md"};function i(l,t,g,d,p,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /40.关于/02.关于本站.md for this page in Markdown format</div><h1 id="关于本站" tabindex="-1">关于本站 <a class="header-anchor" href="#关于本站" aria-label="Permalink to “关于本站”">​</a></h1><p><strong>Insight Stack</strong> 是我的数字花园，也是我践行上述理念的实验场之一。我把它定义为 <strong>&quot;一个探索全栈工程、产品思维与 LLM 交叉领域的数字花园&quot;</strong>。</p><p>这里的 Stack 有两层含义：</p><ul><li><strong>Tech Stack：</strong>硬核的技术积累与工程实践。</li><li><strong>Insight Stack：</strong>软性的思维模型与产品洞察。</li></ul><p>我不希望这里只是枯燥的代码片段或简单的技术分享与总结，我希望你看到的是一个工程师对 <strong>LLM 落地路径</strong>的真实探索，对 <strong>产品 Sense</strong> 这一核心能力的深度复盘，以及个人在技术浪潮中的成长记录。</p><p>值得一提的是，本站也是<strong>人机协作（Human-AI Collaboration）</strong>的产物。 在文章的构思与润色过程中，我深度使用了 Gemini/Claude 等模型作为&quot;主要配角&quot;。我经常与它们发起激烈的&quot;辩论&quot;，利用 AI 来打破思维盲区。我认为，<strong>能够熟练地与 AI 共舞，将是新一代工程师最核心的元能力</strong>。</p><p>当然，一些文章在撰写过程中，我也应用了 AI，甚至用 Gemini3 Pro/Claude 来辅助我创作，并发起过不少&quot;人机辩论&quot;。因为我认为，AI 可以帮助我们更快、更准确地表达自己的思想，也可以帮助我们发现新的角度、新的解决方案。</p><h2 id="❤️-致谢" tabindex="-1">❤️ 致谢 <a class="header-anchor" href="#❤️-致谢" aria-label="Permalink to “❤️ 致谢”">​</a></h2><p><strong>Insight Stack Blog</strong> 博客站点主要基于 <code>VitePress</code> 和 <code>vitepress-theme-teek</code> 搭建而成。</p><img src="'+s+'" style="width:100%;border-radius:8px;margin-bottom:20px;" alt="about site background"><p>特别感谢开源社区赋予我们如此强大的工具，让我能将精力聚焦于内容的创作，而非重复造轮子。本站的核心架构基于以下优秀项目构建：</p><ul><li><strong>Core</strong>: <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>，由 Vite &amp; Vue 驱动的极速静态网站生成器，提供了卓越的开发者体验 (DX) 和极致的性能。</li><li><strong>Theme</strong>: <a href="https://github.com/Kele-Bingtang/vitepress-theme-teek" target="_blank" rel="noreferrer">vitepress-theme-teek</a>，一个专注于阅读体验的 VitePress 自定义主题，其简约的设计理念与本站&quot;注重内容&quot;的初衷不谋而合。</li></ul>',13)])])}const h=e(n,[["render",i]]);export{_ as __pageData,h as default};
